def legendre_symbol(a, p):
    if p < 2 or p % 2 == 0:
        raise ValueError("p must be an odd prime number")

    a %= p

    if a == 0:
        return 0
    if a == 1:
        return 1

    res = 1
    while a % 2 == 0:
        a //= 2
        if p % 8 == 3 or p % 8 == 5:
            res *= -1

    if a == 1:
        return res

    if a % 4 == 3 and p % 4 == 3:
        res *= -1

    return res * legendre_symbol(p % a, a)
